function report = runMultiHarmonicHeightMatrix(options)
%RUNMULTIHARMONICHEIGHTMATRIX Rendered {1,2,4} height-curve controls.
%
% Six radiometry cases and six world-texture cases retain ZNCC, every single
% harmonic, fixed fusion, and hand-gated fusion as separate raw curves. The
% hand gates use known synthetic factor labels and are therefore diagnostic,
% not a deployable estimator. Traceability: algo/main.tex Secs. 8 and 13.3;
% Eqs. (98), (101), (103), (106)-(109), and Algorithm 1.

arguments
    options.ConfigFile (1, 1) string = ""
    options.Display (1, 1) logical = true
end

root = fileparts(fileparts(mfilename("fullpath")));
oldPath = path;
addpath(fullfile(root, "src"));
cleanup = onCleanup(@() path(oldPath));
if strlength(options.ConfigFile) == 0
    options.ConfigFile = fullfile(root, "config", "synthetic", ...
        "pinhole_smoke_96_v1.json");
end

renderer = SyntheticPinholeRenderer.fromJson(options.ConfigFile);
geometry = HeightSweepGeometry( ...
    renderer.ReferenceCamera, renderer.MovingCamera);
p = samplePixels(renderer.ImageSize);
[~, kappa, valid] = PinholePlaneOracle.heightDerivative( ...
    renderer.ReferenceCamera, renderer.MovingCamera, p, ...
    renderer.TrueHeightMetres);
step = renderer.TargetMotionPerLabelPixels ./ median(kappa(valid));
z = heightLabels(renderer.SearchRangeMetres, step);
levels = 2 ^ renderer.BitDepth - 1;

radiometryNames = ["identity", "gain-offset", "gamma", "blur", ...
    "noise", "polarity"];
textureNames = ["natural", "single-edge", "corner", "grid", ...
    "repeated", "low-texture"];
caseCount = numel(radiometryNames) + numel(textureNames);
cases = repmat(emptyCase, caseCount, 1);
caseIndex = 0;

pair = renderer.renderPair;
for k = 1:numel(radiometryNames)
    name = radiometryNames(k);
    moving = SyntheticRadiometry.apply(pair.MovingImage, ...
        renderer.BitDepth, name, Seed=renderer.TextureSeed + 301);
    polarityGate = double(name ~= "polarity");
    quietGate = 1;
    if name == "noise"
        quietGate = 0.25;
    end
    caseIndex = caseIndex + 1;
    cases(caseIndex) = evaluateCase("radiometry", name, pair, moving, ...
        geometry, p, z, levels, polarityGate, 0.5, quietGate, ...
        renderer.TrueHeightMetres);
end

orthogonalGate = [0.25, 0, 1, 1, 0.5, 0];
quietGate = [0.75, 1, 1, 1, 0.5, 0];
for k = 1:numel(textureNames)
    name = textureNames(k);
    pair = renderer.renderPair(TextureType=name);
    caseIndex = caseIndex + 1;
    cases(caseIndex) = evaluateCase("texture", name, pair, ...
        pair.MovingImage, geometry, p, z, levels, 1, ...
        orthogonalGate(k), quietGate(k), renderer.TrueHeightMetres);
end

channels = ["Zncc", "Harmonic1", "Harmonic2", "Harmonic4", ...
    "Fixed124", "Adaptive124"];
rows = cell(caseCount .* numel(channels), 9);
row = 0;
for i = 1:caseCount
    for j = 1:numel(channels)
        row = row + 1;
        metric = cases(i).Metrics.(channels(j));
        good = isfinite(metric.TruthLabelRank);
        uniqueFraction = NaN;
        medianRank = NaN;
        if any(good)
            uniqueFraction = mean(metric.IsUniqueTruthBest(good));
            medianRank = median(metric.TruthLabelRank(good));
        end
        rows(row, :) = {cases(i).Group, cases(i).Name, channels(j), ...
            metric.SelectedHeightErrorMetres(3), ...
            metric.TruthLabelRank(3), mean(good), uniqueFraction, ...
            medianRank, metric.CostAtTruthLabel(3)};
    end
end
results = cell2table(rows, VariableNames=[ ...
    "Group", "Case", "Channel", "CenterSelectedHeightErrorMetres", ...
    "CenterTruthLabelRank", "ValidPointFraction", ...
    "UniqueTruthBestFraction", "MedianTruthLabelRank", ...
    "CenterTruthCost"]);
gates = table(string({cases.Group}).', string({cases.Name}).', ...
    [cases.PolarityGate].', [cases.OrthogonalGate].', ...
    [cases.QuietGate].', VariableNames=["Group", "Case", ...
    "PolarityPreservedProbability", ...
    "OrthogonalStructureProbability", ...
    "LowAngularNoiseProbability"]);

report = struct( ...
    "ConfigurationIdentifier", renderer.Identifier, ...
    "SamplePixels", p, "HeightLabelsMetres", z, ...
    "MedianObservabilityPixelsPerMetre", median(kappa(valid)), ...
    "LabelSpacingMetres", step, ...
    "Cases", cases, "Results", results, "Gates", gates, ...
    "ChannelNames", channels, ...
    "GateDefinition", ...
    "known synthetic factor labels; diagnostic upper bound, not inferred", ...
    "Regularization", "none", ...
    "TotalZnccSeconds", sum([cases.ZnccSeconds]), ...
    "TotalHarmonicSeconds", sum([cases.HarmonicSeconds]));

fprintf("Rendered multi-harmonic matrix: %d cases, %d channels\n", ...
    caseCount, numel(channels));
disp(results(:, ["Group", "Case", "Channel", ...
    "CenterSelectedHeightErrorMetres", "CenterTruthLabelRank", ...
    "UniqueTruthBestFraction"]));
fprintf("  Runtime: ZNCC %.3f s, multi-harmonic %.3f s\n", ...
    report.TotalZnccSeconds, report.TotalHarmonicSeconds);
if options.Display
    showCurves(report, renderer.TrueHeightMetres);
end

clear cleanup
end

function out = evaluateCase(group, name, pair, moving, geometry, p, z, ...
        levels, polarityGate, orthogonalGate, quietGate, truthHeight)
base = HeightCostCurve(geometry, ...
    double(pair.ReferenceImage) ./ levels, double(moving) ./ levels, ...
    DerivativeSigma=1, IntegrationSigma=2, ...
    ReferenceValid=pair.ReferenceValid, MovingValid=pair.MovingValid);
timer = tic;
zncc = base.evaluate(p, z, Channels="Zncc", ...
    MinimumSupportFraction=0.95);
znccSeconds = toc(timer);
curve = MultiHarmonicHeightCurve(base);
timer = tic;
harmonic = curve.evaluate(p, z, MinimumSupportFraction=0.95, ...
    FixedWeights=[1, 1, 1], ...
    PolarityPreservedProbability=polarityGate, ...
    OrthogonalStructureProbability=orthogonalGate, ...
    LowAngularNoiseProbability=quietGate);
harmonicSeconds = toc(timer);

combined = harmonic;
combined.Costs = struct("Zncc", zncc.Costs.Zncc, ...
    "Harmonic1", harmonic.Costs.Harmonic1, ...
    "Harmonic2", harmonic.Costs.Harmonic2, ...
    "Harmonic4", harmonic.Costs.Harmonic4, ...
    "Fixed124", harmonic.Costs.Fixed124, ...
    "Adaptive124", harmonic.Costs.Adaptive124);
combined.SelectedHeight.Zncc = zncc.SelectedHeight.Zncc;
combined.Valid.Zncc = zncc.Valid.Zncc;
combined.SupportFraction.Zncc = zncc.SupportFraction.Zncc;
metrics = HeightCostMetrics.analyze(combined, ...
    repmat(truthHeight, size(p, 1), 1));
out = struct("Group", group, "Name", name, ...
    "PolarityGate", polarityGate, ...
    "OrthogonalGate", orthogonalGate, "QuietGate", quietGate, ...
    "CostCurve", combined, "Metrics", metrics, ...
    "ZnccSeconds", znccSeconds, "HarmonicSeconds", harmonicSeconds);
end

function c = emptyCase()
c = struct("Group", "", "Name", "", "PolarityGate", NaN, ...
    "OrthogonalGate", NaN, "QuietGate", NaN, ...
    "CostCurve", struct, "Metrics", struct, ...
    "ZnccSeconds", NaN, "HarmonicSeconds", NaN);
end

function p = samplePixels(imageSize)
cx = (imageSize(2) + 1) ./ 2;
cy = (imageSize(1) + 1) ./ 2;
d = 0.18 .* [imageSize(2), imageSize(1)];
p = [cx - d(1), cy; cx, cy - d(2); cx, cy; ...
    cx, cy + d(2); cx + d(1), cy];
end

function z = heightLabels(range, step)
n0 = floor(abs(range(1)) ./ step);
n1 = floor(abs(range(2)) ./ step);
z = (-n0:n1) .* step;
end

function showCurves(report, truth)
for group = ["radiometry", "texture"]
    figure(Name="Multi-harmonic " + group + " raw height costs");
    tiledlayout(2, 3);
    indices = find(string({report.Cases.Group}) == group);
    for i = indices
        nexttile;
        hold on;
        for channel = report.ChannelNames
            plot(report.HeightLabelsMetres, ...
                report.Cases(i).CostCurve.Costs.(channel)(3, :), ...
                LineWidth=1);
        end
        xline(truth, "--k", "Truth");
        grid on;
        xlabel("Elevation Z (m)");
        ylabel("Unregularized cost");
        title(report.Cases(i).Name);
    end
    legend(report.ChannelNames, Location="eastoutside");
end
end
